import sys
from functools import lru_cache

def main():
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    cards = []
    index = 1
    for i in range(N):
        A = int(data[index])
        B = int(data[index + 1])
        cards.append((A, B))
        index += 2

    # Precompute all valid pairs
    valid_pairs = []
    for i in range(N):
        for j in range(i + 1, N):
            if cards[i][0] == cards[j][0] or cards[i][1] == cards[j][1]:
                valid_pairs.append((i, j))

    @lru_cache(maxsize=None)
    def dfs(mask):
        # Find the first available pair
        for i in range(N):
            if not (mask & (1 << i)):
                continue
            for j in range(i + 1, N):
                if not (mask & (1 << j)):
                    continue
                if cards[i][0] == cards[j][0] or cards[i][1] == cards[j][1]:
                    new_mask = mask & ~((1 << i) | (1 << j))
                    if dfs(new_mask) is False:
                        return True
        return False

    initial_mask = (1 << N) - 1
    if dfs(initial_mask):
        print("Takahashi")
    else:
        print("Aoki")

if __name__ == "__main__":
    main()
